css:
/* ===== 字体 ===== */
@font-face {
    font-family: "Jing Hua ";
    src: url("https://files.catbox.moe/138mza.ttf") format("truetype");
}
body {
    font-family: "Jing Hua ", sans-serif;
}

code {
    background-color: rgb(206 217 181 / 78%);
    color: rgb(99 130 34);
}


/* 斜体 */
.mes_text em {
    color: var(--SmartThemeEmColor);
    text-decoration: underline;
    text-decoration-color: #92a281c2;
    text-decoration-thickness: 2px;
}

/* 引用 */
.mes_text q {
    color: var(--SmartThemeQuoteColor);
    background-color: rgba(229,235,207,0.7); /* 深灰色背景 */
    border-radius: 15px; /* 圆角效果改为15px */
    padding: 0px 0px; /* 恢复适当的内边距 */
    display: inline;
    box-decoration-break: clone;
    -webkit-box-decoration-break: clone;
}
/* 代码块 */
.mes_text pre,
.mes_reasoning pre {
background: url('https://i.postimg.cc/Hn4m8nys/73ce1b37ff7eaa341da51f77508cfc83.jpg') repeat;
background-size: 40px 100px;
padding: 15px 10px 10px;
border-radius: 15px;
margin: 15px 0 0;
position: relative;
box-sizing: border-box;
}
.mes_text pre::after,
.mes_reasoning pre::after {
  content: "";
  position: absolute;
  top: -15px;
  left: 50%;
  transform: translateX(-50%);
  width: 30px;
  height: 30px;
  background: url('https://i.postimg.cc/VLZwNKtb/IMG-2257.png') no-repeat center;
  background-size: contain;
}

.mes_text pre code,
.mes_reasoning pre code {
  background-color: #fff9f9;
  color: #547430;
  box-sizing: border-box;
  border-radius: 12px; /* 去除圆角效果 */
}

#chat > div > div.mes_block > div.mes_text > pre > code > i {
  font-size: 0; /* 隐藏原图标内容 */
  display: inline-block;
  width: 20px;
  height: 20px;
  background: url('https://i.postimg.cc/25WPRDdM/IMG-2265.png') no-repeat center;
  background-size: contain;
  vertical-align: middle;
}

/*引用块*/
.mes_text blockquote, .mes_reasoning blockquote {
    background-color: rgb(117 158 78 / 10%);
    border-radius: 5px;
}


/* ===== 动画 ===== */
/* 移除原始伪元素 */
#load-spinner ,#load-spinner::before{
   animation: none;
   content: "";
}

/* 创建新的自定义加载动画 */
#load-spinner::after {
    content: "";
    position: absolute;
    top: 50%;
    left: 50%;
    width: 60px;
    height: 60px;
    background: url('https://i.postimg.cc/cH1FJGyf/IMG-2263.png') center/contain no-repeat;
    transform: translate(-50%, -50%);
    z-index: 1000;
    /* 添加左右旋转摇晃动画 */
    animation: rotate-shake 3s ease-in-out infinite;
}

/* 左右旋转摇晃动画关键帧 */
@keyframes rotate-shake {
    0%, 100% {
        transform: translate(-50%, -50%) rotate(0deg);
    }
    25% {
        transform: translate(-50%, -50%) rotate(-15deg);
    }
    50% {
        transform: translate(-50%, -50%) rotate(0deg);
    }
    75% {
        transform: translate(-50%, -50%) rotate(15deg);
    }
}

/* 隐藏原有旋转动画 */
@keyframes custom-spin {
    display: none;
}
/* ===== 思维块美化 ===== */
.mes_reasoning_header {
    cursor: pointer;
    position: relative;
    left: 50%; /* 水平居中 */
    transform: translate(-50%, -50%); /* 精确居中 */
    user-select: none;
    margin: 5px;
    padding: 2px 8px;
    padding-right: calc(0.7em + 14px);
    background-color: #B0BB8E; /* 背景颜色 */
    border: 2px dashed #637639; /* 虚线外勾边 */
    border-radius: 20px; /* 圆角20px */
    font-size: calc(var(--mainFontSize) * 0.9);
    color: #637639;
    align-items: baseline;
    /* Empty the content */
    font-size: 0 !important;
}

.mes_reasoning_header::before {
    content: "今日食谱揭秘"; /* 修改文字内容 */
    font-size: calc(var(--mainFontSize) * 0.9);
    display: inline;
}

.fa-chevron-up:before {
    content: ""; /* 去除原有样式 */
}

.fa-chevron-up::before {
    content: "";
    display: inline-block;
    width: 10px;
    height: 10px;
    background-image: url("https://i.postimg.cc/25WPRDdM/IMG-2265.png");
    background-size: 10px 10px;
    background-repeat: no-repeat;
}

/* ====== 气泡 ====== */


.mes_block {
    padding-left: 0;
}

body.bubblechat .mes, body.bubblechat .mes[is_user="true"] {
    padding: 13px;
    border-radius: 0px;
    margin-bottom: 5px;
    border: 1px solid var(--SmartThemeBorderColor);
    max-width: 330px;
    margin: 210px auto 45px auto;
    position: relative;
    /* 添加背景图片 */
    background-image: url("https://i.postimg.cc/XvgWHpv1/434152332b649290f925c632c0c9cd24.png");
    background-size: 330px 99px;
    background-repeat: repeat;
    background-position: center;
}

.mes {
    --swipeCounterHeight: 15px;
    --swipeCounterMargin: 5px;
    display: flex;
    align-items: flex-start;
    padding: 13px 13px 0;
    margin: 210px auto 45px auto;
    width: 330px;
    max-width: 330px;
    color: var(--SmartThemeBodyColor);
    position: relative;
    background-color: rgba(79, 37, 33, 1);
    /* 添加背景图片 */
    background-image: url("https://i.postimg.cc/XvgWHpv1/434152332b649290f925c632c0c9cd24.png");
    background-size: 330px 99px;
    background-repeat: repeat;
    background-position: center;
}

.last_mes {
    margin-bottom: 0 !important;
}

/* 为所有气泡添加顶部图片 */
.mes::before {
    content: "";
    position: absolute;
    top: -198px; /* 图片高度 */
    width: 330px;
    height: 198px;
    left: 50%;
    transform: translateX(-50%);
    background-image: url("https://i.postimg.cc/k4fn4B3c/e1eeecb70c7af7341208eecf6431adf7.png");
    background-size: 330px 198px; 
    background-repeat: no-repeat;
    background-position: center;
    z-index: 0;
}

/* 为所有气泡添加底部图片 */
.mes::after {
    content: "";
    position: absolute;
    bottom: -44px; 
    width: 330px;
    height: 44px;
    left: 50%;
    transform: translateX(-50%);
    background-image: url("https://i.postimg.cc/1tf98y9v/7610683da045ade27b7388a36db58db2.png");
    background-size: 330px 44px; 
    background-repeat: no-repeat;
    background-position: center;
    z-index: 1;
}

/* 翻页 */
.swipe_left {
    left: 50px;
    bottom:-30px;
}
.swipe_right {
    position: absolute;
    right: 50px;
    bottom:-30px;
}

.fa-chevron-right:before {
    right: 50px;
    bottom:-30px;
    content: "";
    display: inline-block;
    width: 20px;
    height: 20px;
    background-image: url("https://i.postimg.cc/hPzjzJKf/IMG-2271.png");
    background-size: contain;
    background-repeat: no-repeat;
    background-position: center;
    vertical-align: middle;
}

.fa-chevron-left:before {
    content: "";
    display: inline-block;
    width: 20px;
    height: 20px;
    background-image: url("https://i.postimg.cc/hPzjzJKf/IMG-2271.png");
    background-size: contain;
    background-repeat: no-repeat;
    background-position: center;
    vertical-align: middle;
}

/* 文本 */
.mes_text {
    padding-left: 5px;
    padding-top: 5px;
    padding-bottom: 5px;
    padding-right: 5px;
}

/*幽灵*/
.fa-ghost:before {
  content: "";
  display: inline-block;
  width: 25px;
  height: 25px;
  background: url('https://i.postimg.cc/TwT33740/IMG-2259.png') no-repeat center;
  background-size: contain;
  vertical-align: middle;
}

.reasoning_edit_textarea, .edit_textarea {
    background-color: rgb(234 216 216 / 50%);
}
/* ====== 头像 ====== */
.mesAvatarWrapper {
    width: 90px;
    height: 90px;
    object-fit: cover;
    display: block;
    position: absolute;
    left: 198px;
    top: -115px; /* 微调位置使头像底部高于消息15px */
}

.mesAvatarWrapper .avatar img {
width: 180%;
height: 180%;
object-fit: cover;
border-radius: inherit;
}

/* 覆盖图片 */
.mesAvatarWrapper::after {
    content: ""; /* 确保伪元素有内容 */
    position: absolute;
    left: 50%;
    top: 50%; /* 添加垂直居中定位 */
    transform: translate(-50%, -50%); /* 同时调整水平和垂直偏移 */
    width: 105px;
    height: 105px;
    background-image: url("https://i.postimg.cc/htfMZwPp/IMG-2249.png");
    background-size: cover;
    background-position: center;
    z-index: 2; /* 覆盖头像 */
    pointer-events: none; /* 防止影响点击 */
}


.mes .mes_timer {
    cursor: default;
    opacity: 0.7;
    font-size: calc(var(--mainFontSize) * 0.75);
    font-weight: 600;
    text-align: right;
    position: absolute;
    right: 103px;
    white-space: nowrap; /* 防止换行 */
    top: 66px;
    z-index: 10;
}


.mes .mesIDDisplay {
    cursor: default;
    opacity: 0.7;
    font-size: calc(var(--mainFontSize) * 0.75);
    font-weight: 600;
    text-align: right;
    position: absolute;
    white-space: nowrap; /* 防止换行 */
    right: 103px;
    top: 52px;    
    z-index: 10;
}


.mes .tokenCounterDisplay {
    cursor: default;
    opacity: 0.7;
    font-size: calc(var(--mainFontSize) * 0.75);
    font-weight: 600;
    text-align: right;
    position: absolute;
    right: 103px; 
    text-align: right; /* 右对齐 */
    white-space: nowrap; /* 防止换行 */
    top: 34px;
    z-index: 10;
}
.mes .tokenCounterDisplay::before {
    content: " ……";
    display: inline;
}

/* 时间戳位置 */
.mes .timestamp {
    font-size: calc(var(--mainFontSize) * 0.7);
    font-weight: 600;
    position: absolute; /* 绝对定位 */
    right: 50%; 
    top: -30px; /* Y轴偏移-40px */
    text-align: right; /* 右对齐 */
    white-space: nowrap; /* 防止换行 */
    z-index: 10; /* 确保显示在最前面 */
    opacity: 0.7; /* 保持原有透明度 */
}



.mes .name_text {
    font-size: calc(var(--mainFontSize) * 0.7);
    position: absolute; /* 绝对定位 */
    left: 30px;
    top: -112.5px; /* Y轴向上偏移165px */
    text-align: center; 
    white-space: nowrap; /* 防止换行 */
    z-index: 10; /* 确保显示在最前面 */
    cursor: default;
    opacity: 0.7;
    font-weight: 600;
}

.mes_block {
  transform: none !important;
}

/* ===== 底部输入栏 ===== */
#qr--bar {
    outline: none;
    margin: 0;
    transition: 0.3s;
    opacity: 0.7;
    display: flex;
    align-items: center;
    justify-content: center;
    top:5px ;
    width: 100%;
    max-width: 100%;
    /* 修改高度为自适应 */
    height: auto;
    /* 设置最大高度并允许垂直滚动 */
    max-height: 30px; /* 保留原始高度作为最大高度 */
    /* 允许水平和垂直方向滚动 */
    overflow: auto; /* 替代原来的overflow-x和overflow-y */
    scrollbar-width: thin;
    scrollbar-color: #888 #f0f0f0;
}

/* 统一滚动条样式 */
#qr--bar::-webkit-scrollbar {
    width: 4px;  /* 垂直滚动条宽度 */
    height: 4px; /* 水平滚动条高度 */
}

#qr--bar::-webkit-scrollbar-track {
    background: #f0f0f0;
}

#qr--bar::-webkit-scrollbar-thumb {
    background-color: #888;
    border-radius: 2px;
}

#send_form {
    display: flex;
    flex-wrap: wrap;
    align-items: center;
    width: 100%;
    margin: 0px auto 0px auto; /* 上下边距15px */
    border: 1px solid var(--SmartThemeBorderColor);
    border-radius: 0; /* 四个角的圆角度数为0 */
    backdrop-filter: blur(var(--SmartThemeBlurStrength));
    position: relative; /* 为内勾边定位做准备 */
}

#nonQRFormItems {
    padding: 5px;
    border: 0;
    position: relative;
    background-image: url("https://i.postimg.cc/B6QhMQW4/cb87912d243e9ae2fd6be016285a1986.jpg"); /* 添加背景图片 */
    background-size: 90px 30px; /* 设置背景图片大小 */
    background-repeat: repeat; /* 平铺 */
    background-position: center;
    display: flex;
    flex-direction: row;
    column-gap: 5px;
    font-size: var(--bottomFormIconSize);
    order: 25;
    width: 100%;
    min-height: 30px;
    align-items: center;
    overflow: hidden;
}
#nonQRFormItems textarea {
    flex: 1;
    min-height: 30px;
    max-height: 100px;
    resize: none;
    overflow-y: auto;
    line-height: normal;
    padding: 5px;
    margin: 0;
    border: none;
    outline: none;
    background: rgba(255, 255, 255, 0.7) !important;
}
#nonQRFormItems textarea::before {
    content: "𓇬₊˚𝒫𝒾𝓃𝓀 𝐸𝓉𝑒𝓇𝓃𝒶𝓁 𝒪𝒶𝓉𝒽˚.⟡";
    font-family: 'CustomFont', sans-serif;
    color: #B28484;
}

/* 字体图标容器固定大小 */
#nonQRFormItems .icon-container {
    display: flex;
    align-items: center;
    justify-content: center;
    height: 30px;
    width: 30px; /* 固定宽度 */
    flex-shrink: 0; /* 防止图标被压缩 */
}

#qr--bar > .qr--buttons .qr--button, #qr--popout > .qr--body > .qr--buttons .qr--button{
    transform: scale(0.9);
}


/*停止钮*/
.fa-circle-stop:before,
.fa-stop-circle:before {
  content: ""; /* 移除原图标 */
  display: inline-block;
  width: 30px;
  height: 30px;
  background: url('https://i.postimg.cc/cH1FJGyf/IMG-2263.png') no-repeat center;
  background-size: contain;
  opacity: 1;
  animation: rotateShake 1.5s ease-in-out infinite; /* 增加持续时间到1.5秒 */
  transform-origin: center; /* 设置旋转中心 */
}

@keyframes rotateShake {
  0%, 100% {
    transform: rotate(0deg);
  }
  25% {
    transform: rotate(-10deg); /* 向左旋转 */
  }
  75% {
    transform: rotate(10deg); /* 向右旋转 */
  }
}

/*小飞机*/
.fa-paper-plane:before {
  content: "";
  display: inline-block;
  width: 30px;
  height: 30px;
  background: url('https://i.postimg.cc/cH1FJGyf/IMG-2263.png') no-repeat center;
