input[type="range"] {
    -webkit-appearance: none;
    appearance: none;
    margin: 0;
    padding: 0;
    width: 100%;
    height: 5px;
    background: var(--white50a);
    border-radius: 15px;
    background-size: 70% 100%;
    background-repeat: no-repeat;
    cursor: ew-resize;
    /* 移除可能的阴影 */
    box-shadow: none;
}

/* Webkit浏览器滑块样式 */
input[type="range"]::-webkit-slider-thumb {
    -webkit-appearance: none;
    appearance: none;
    width: 20px;
    height: 20px;
    background: url('https://i.postimg.cc/25WPRDdM/IMG-2265.png') center/contain no-repeat;
    cursor: pointer;
    border: none;
    /* 移除滑块阴影 */
    box-shadow: none;
}

/* Firefox浏览器滑块样式 */
input[type="range"]::-moz-range-thumb {
    width: 20px;
    height: 20px;
    background: url('https://i.postimg.cc/j2F4tMGf/IMG-2201.png') center/contain no-repeat;
    cursor: pointer;
    border: none;
    /* 移除滑块阴影 */
    box-shadow: none;
}

/* 针对IE浏览器（如果需要） */
input[type="range"]::-ms-thumb {
    box-shadow: none;
}

/* 图标 */

.fa-bars:before, .fa-navicon:before {
    content: ""; /* 移除原有图标 */
    display: inline-block;
    width: 25px;
    height: 25px;
    background: url('https://i.postimg.cc/L8Sp9h5s/IMG-2268.png') center/contain no-repeat;
    vertical-align: middle;
}

.fa-magic-wand-sparkles:before, .fa-wand-magic-sparkles:before {
    content: ""; /* 移除原有图标 */
    display: inline-block;
    width: 25px;
    height: 25px;
    background: url('https://i.postimg.cc/VkhW90CH/IMG-2269.png') center/contain no-repeat;
    vertical-align: middle;
}

.drawer-content select {
    background-color: #d8e5c2;
    border-radius: 10px;
}

/*滑动块底色*/
.neo-range-input, #completion_prompt_manager #completion_prompt_manager_list {
    background-color: #e5edd161;
}

/* css修改文本框 */
textarea, .textarea_compact, .range-block-counter input, .text_pole {
    background-color: #e8f3e2;
    color: rgb(112 153 78);
}

 #completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt_disabled .completion_prompt_manager_prompt_name .prompt-manager-inspect-action {
    color: #C5C5C5;
}

#completion_prompt_manager .completion_prompt_manager_header div {
    color: #889c7c;
}
#completion_prompt_manager .completion_prompt_manager_header_advanced span {
    filter:none;
}

/*预设正则空间预留*/
#global_scripts_block ,#scoped_scripts_block ,#completion_prompt_manager_list{
    padding-right: 20px;
}

/*热切换*/
#HotSwapWrapper {
    position: relative;
    overflow-x: auto;
    scrollbar-width: thin; /* Firefox */
    scrollbar-color: rgba(255, 182, 193, 0.3) 
}

#HotSwapWrapper::-webkit-scrollbar {
    height: 1px; /* 设置滚动条高度为3px */
}

#HotSwapWrapper::-webkit-scrollbar-track {
    background: transparent; /* 滚动条轨道透明 */
}

#HotSwapWrapper::-webkit-scrollbar-thumb {
    scrollbar-color: rgba(255, 182, 193, 0.3) 
    border-radius: 0; /* 无圆角 */
    border: none; /* 无边框 */
}

#HotSwapWrapper > * {
    flex-shrink: 0;
}



/* 底栏QR按键隐藏 */
#send_form:hover #qr--bar {
    height: 40px;
    opacity: 1; /* 显示时不透明 */
}

#qr--bar {
    height: 0 ;
    transition: none; /* 确保没有过渡效果 */
    opacity: 0; /* 隐藏时透明 */
}

.reverse_proxy_warning:not(small) {
    color: rgb(202 147 147 / 90%);
}


/* 全局滑动条样式 */
::-webkit-scrollbar {
    width: 1px; /* 滑动条宽度 */
    height: 1px; /* 水平滑动条高度 */
}

::-webkit-scrollbar-track {
    background: transparent; /* 轨道背景透明 */
}

::-webkit-scrollbar-thumb {
    background: rgba(170, 185, 108, 0.3); /* 半透明浅粉色 */
    border-radius: 0; /* 无圆角 */
}

::-webkit-scrollbar-thumb:hover {
    background: rgba(170, 185, 108, 0.3); /* 鼠标悬停时稍微加深 */
}

/* Firefox 浏览器 */
* {
    scrollbar-width: thin; /* 细滚动条 */
    scrollbar-color: rgba(170, 185, 108, 0.3) transparent; /* 滑块半透明浅粉色，轨道透明 */
}

/* 分割线 */
hr {
    background-image: url("https://i.postimg.cc/k4qtt6VG/IMG-2250.png");
    background-size: 100px 25px; /* 设置图片大小 */
    background-repeat: repeat; /* 平铺效果 */
    margin: 5px 0;
    height: 25px; /* 设置高度为30px */
    min-height: 25px; /* 最小高度也为30px */
    border: 0;
    opacity: 0.8;
}

body.bubblechat .welcomePanel {
    backdrop-filter: blur(10px);
    -webkit-backdrop-filter: blur(10px);
    background-color: rgba(255, 255, 255, 0.7);
}

.select2-container .select2-selection--multiple, .select2-container .select2-selection--single {
    background-color: rgb(0 0 0 / 0%);
}

.select_chat_block[highlight] {
    background-color: rgb(96 110 86 / 30%);
}

.reverse_proxy_warning:not(small) {
    background-color: rgb(208 216 182 / 70%);
}
